sys_script.script:
(function executeRule(current, previous) {
  // --- 1. Create Processing Job ---
  var job = new GlideRecord('x_1845356_circle_0_processing_job');
  job.initialize();
  job.setValue('device_record', current.getUniqueValue());
  job.setValue('job_type', current.getValue('triage_decision'));
  job.setValue('status', 'open');
  job.setValue('start_date', new GlideDateTime());
  var jobSysId = job.insert();

  if (!jobSysId) {
    gs.error('CircleBack Triage Router: Failed to create Processing Job for Device Record ' + current.getValue('device_id'));
    return;
  }

  gs.info('CircleBack Triage Router: Created Processing Job for Device ' + current.getValue('device_id') + ' with decision ' + current.getValue('triage_decision'));

  // --- 2. Mark triage as completed on current Device Record ---
  var deviceGr = new GlideRecord('x_1845356_circle_0_device_record');
  if (deviceGr.get(current.getUniqueValue())) {
    deviceGr.setValue('triage_completed', true);
    deviceGr.setWorkflow(false);
    deviceGr.update();
  }

  // --- 3. Update linked Return Request to In Processing ---
  var returnRequestSysId = current.getValue('return_request');
  if (returnRequestSysId) {
    var rr = new GlideRecord('x_1845356_circle_0_return_request');
    if (rr.get(returnRequestSysId)) {
      rr.setValue('status', 'in_processing');
      rr.update();
      gs.info('CircleBack Triage Router: Return Request ' + rr.getValue('return_reference') + ' advanced to In Processing');
    }
  }
})(current, previous);
